  panda watch list [--status enabled|disabled|all] [--limit <n>]
  panda watch show <watch-id>
  panda watch runs <watch-id> [--limit <n>]
  panda watch create --title <text|@file|@-> --every <minutes> (--url <url> --value-path <path> --percent-change <n> [--label <text|@file|@->]|--source-json <json|@file|@-> --detector-json <json|@file|@-> [--source-kind <kind>] [--detector-kind <kind>]) [--disabled]
  panda watch update <watch-id> [--title <text|@file|@->] [--every <minutes>] [--url <url> --value-path <path> [--label <text|@file|@->]] [--percent-change <n>] [--source-json <json|@file|@->] [--detector-json <json|@file|@->] [--source-kind <kind>] [--detector-kind <kind>] [--enable|--disable]
  panda watch disable <watch-id> [--reason <text|@file|@->]
