  panda schedule update <task-id> [--title <text|@file|@->] [--at <iso>|--cron <expr> --timezone <tz>] [--instruction <text|@file|@->] [--enable|--disable]
  panda schedule cancel <task-id> [--reason <text|@file|@->]
