agent_command_shim_print_root_usage_examples() {
  cat <<'PANDA_COMMAND_ROOT_USAGE_EXAMPLES'
  panda time now --timezone UTC --format iso
  panda web fetch https://example.com
  panda brave web search 'latest TypeScript release' -n 5 --freshness pw
  panda brave llm context 'best durable command CLI design' --max-tokens 8192 --threshold strict
  panda openai web-research 'latest TypeScript release' --effort medium
  panda watch create --title PandaStars --every 60 --url https://api.github.com/repos/patrikmojzis/panda-agent --value-path stargazers_count --label stars --percent-change 10
  panda watch runs watch_123 --limit 10
  panda schedule create "check CI" --at 2026-05-25T09:00:00+02:00 --instruction "Check CI status"
  panda micro-app view food-tracker today_summary
  panda environment create --label review --ttl 24h
  cat note.txt | panda vent --stdin
  cat SKILL.md | panda skill set calendar --description "Use this for calendar work." --content @-
  cat query.sql | panda postgres readonly query --sql @-
  panda wiki read agents/panda/profile
  cat facts.md | panda wiki write section agents/panda/profile Facts --content @-
  cat brief.md | panda session prompt current set brief --content @-
  panda todo add "Inspect code"
  panda subagent spawn "Inspect the runtime wiring." --profile workspace
  panda a2a send --to-session session-b --text "done"
  panda email send --account work --to alice@example.com --subject Report --text @body.txt --file ./report.pdf
  cat message.md | panda telegram send --chat 12345 --connector telegram-main --text @- --file ./report.pdf
  cat message.md | panda discord send --channel 12345 --connector discord-main --text @- --file ./report.pdf
  cat message.md | panda whatsapp send --chat 421900000000 --connector main --text @- --file ./report.pdf
  printf '%s' "$GITHUB_TOKEN" | panda env set GITHUB_TOKEN --stdin
  panda image generate --prompt 'Restyle this as a pencil sketch' --image ./reference.png
  panda whisper transcribe ./voice.mp3 --prompt @terms.txt
  panda whisper translate ./voice.mp3 --prompt @terms.txt
PANDA_COMMAND_ROOT_USAGE_EXAMPLES
}

